/* global console, process */
import { spawn } from 'node:child_process';
import { existsSync } from 'node:fs';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterRuntimePath = existsSync(monsterPath) ? monsterPath : gnexecPath;

if (!existsSync(monsterRuntimePath)) {
  console.error(`Monster runtime not found at ${monsterRuntimePath}`);
  process.exit(1);
}

// Test user IDs for foil fanout
const testUserIds = Array.from({ length: 100 }, (_, i) => `user${i}`);

const modes = {
  naive: {
    label: 'NAIVE',
    env: { FOIL_NAIVE: '1' },
  },
  helix: {
    label: 'HELIX',
    env: {},
  },
  probability: {
    label: 'PROBABILITY',
    env: { FOIL_NAIVE: '1', GNEXEC_FOIL_PROBABILITY_ROUTE_CACHE: '1' },
  },
};

function envInteger(name, fallback) {
  const value = Number.parseInt(process.env[name] ?? '', 10);
  return Number.isFinite(value) && value > 0 ? value : fallback;
}

function percentile(sorted, ratio) {
  if (sorted.length === 0) return 0;
  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(latencies) {
  const sorted = [...latencies].sort((a, b) => a - b);
  const sum = sorted.reduce((acc, v) => acc + v, 0);
  return {
    count: sorted.length,
    p50_us: percentile(sorted, 0.50),
    p95_us: percentile(sorted, 0.95),
    p99_us: percentile(sorted, 0.99),
    max_us: sorted[sorted.length - 1] ?? 0,
    mean_us: sum / Math.max(1, sorted.length),
  };
}

async function runMonsterResident(requests, env = {}) {
  return new Promise((resolve, reject) => {
    const child = spawn(monsterRuntimePath, [
      '--resident-jsonl',
      path.resolve(__dirname, 'fanout.ts'),
    ], {
      env: { ...process.env, ...env },
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    const results = [];
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');

    child.stdout.on('data', (chunk) => {
      chunk.trim().split('\n').forEach(line => {
        if (line) {
          try {
            const obj = JSON.parse(line);
            if (obj.ok && obj.elapsed_ns !== undefined) {
              results.push(obj.elapsed_ns / 1000); // Convert ns to µs
            }
          } catch (e) {
            // Ignore parse errors
          }
        }
      });
    });

    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });

    child.on('error', reject);
    child.on('close', (code) => {
      if (code !== 0 && stderr) {
        reject(new Error(`Process exited with code ${code}: ${stderr}`));
      } else {
        resolve(results);
      }
    });

    // Send requests
    setImmediate(() => {
      requests.forEach((userId, index) => {
        const line = JSON.stringify({ userId, index });
        child.stdin.write(line + '\n');
      });
      child.stdin.end();
    });
  });
}

async function runBurstWorkload(modeName) {
  const mode = modes[modeName];
  const requestCount = envInteger('MONSTER_P99_BURST_REQUESTS', 8192);
  console.log(`\n🔫 BURST WORKLOAD (${requestCount} requests fired simultaneously) [${mode.label}]`);
  const requests = Array.from({ length: requestCount }, (_, i) =>
    testUserIds[i % testUserIds.length]
  );

  const latencies = await runMonsterResident(requests, mode.env);
  const stats = summarize(latencies);

  console.log(`  Requests: ${stats.count}`);
  console.log(`  p50: ${stats.p50_us.toFixed(1)} µs`);
  console.log(`  p95: ${stats.p95_us.toFixed(1)} µs`);
  console.log(`  p99: ${stats.p99_us.toFixed(1)} µs`);
  console.log(`  max: ${stats.max_us.toFixed(1)} µs`);
  console.log(`  mean: ${stats.mean_us.toFixed(1)} µs`);

  return stats;
}

async function runSustainedWorkload(modeName) {
  const mode = modes[modeName];
  const requestsPerSecond = envInteger('MONSTER_P99_SUSTAINED_RPS', 5000);
  const durationSeconds = envInteger('MONSTER_P99_SUSTAINED_SECONDS', 10);
  const totalRequests = requestsPerSecond * durationSeconds;
  console.log(`\n📊 SUSTAINED WORKLOAD (${totalRequests} requests over ${durationSeconds}s) [${mode.label}]`);

  const requests = Array.from({ length: totalRequests }, (_, i) =>
    testUserIds[i % testUserIds.length]
  );

  const latencies = await runMonsterResident(requests, mode.env);
  const stats = summarize(latencies);

  console.log(`  Requests: ${stats.count}`);
  console.log(`  p50: ${stats.p50_us.toFixed(1)} µs`);
  console.log(`  p95: ${stats.p95_us.toFixed(1)} µs`);
  console.log(`  p99: ${stats.p99_us.toFixed(1)} µs`);
  console.log(`  max: ${stats.max_us.toFixed(1)} µs`);
  console.log(`  mean: ${stats.mean_us.toFixed(1)} µs`);

  return stats;
}

async function runMixedWorkload(modeName) {
  const mode = modes[modeName];
  // 80% arrive in a burst, 20% arrive steadily
  const totalRequests = envInteger('MONSTER_P99_MIXED_REQUESTS', 10000);
  const burstCount = Math.floor(totalRequests * 0.8); // 8000
  const steadyCount = totalRequests - burstCount; // 2000
  console.log(`\n🔀 MIXED WORKLOAD (80% burst, 20% sustained, ${totalRequests} total) [${mode.label}]`);

  const requests = [
    ...Array.from({ length: burstCount }, (_, i) => testUserIds[i % testUserIds.length]),
    ...Array.from({ length: steadyCount }, (_, i) => testUserIds[i % testUserIds.length]),
  ];

  const latencies = await runMonsterResident(requests, mode.env);
  const stats = summarize(latencies);

  console.log(`  Requests: ${stats.count}`);
  console.log(`  p50: ${stats.p50_us.toFixed(1)} µs`);
  console.log(`  p95: ${stats.p95_us.toFixed(1)} µs`);
  console.log(`  p99: ${stats.p99_us.toFixed(1)} µs`);
  console.log(`  max: ${stats.max_us.toFixed(1)} µs`);
  console.log(`  mean: ${stats.mean_us.toFixed(1)} µs`);

  return stats;
}

async function main() {
  console.log('🔫 Monster p99 Cannon — HELIX Admission Control Regime Change Detector');
  console.log('======================================================================');

  try {
    // Run naive baseline first, then HELIX-controlled and probability-routed runs.
    console.log('\n[BASELINE RUNS — FOIL_NAIVE enabled, no admission control]');
    const naiveResults = {
      burst: await runBurstWorkload('naive'),
      sustained: await runSustainedWorkload('naive'),
      mixed: await runMixedWorkload('naive'),
    };

    console.log('\n[HELIX-CONTROLLED RUNS — admission gates staggers foil work by 5µs]');
    const helixResults = {
      burst: await runBurstWorkload('helix'),
      sustained: await runSustainedWorkload('helix'),
      mixed: await runMixedWorkload('helix'),
    };

    console.log('\n[PROBABILITY-ROUTED RUNS — observed hot keys reuse folded fanout results]');
    const probabilityResults = {
      burst: await runBurstWorkload('probability'),
      sustained: await runSustainedWorkload('probability'),
      mixed: await runMixedWorkload('probability'),
    };

    // Summary comparison
    console.log('\n======================================================================');
    console.log('REGIME CHANGE ANALYSIS');
    console.log('======================================================================\n');

    ['burst', 'sustained', 'mixed'].forEach(workload => {
      const naive = naiveResults[workload];
      const helix = helixResults[workload];
      const probability = probabilityResults[workload];

      console.log(`${workload.toUpperCase()}:`);
      console.log(`  Naive p99:        ${naive.p99_us.toFixed(1)} µs`);
      console.log(`  HELIX p99:        ${helix.p99_us.toFixed(1)} µs`);
      console.log(`  Probability p99:  ${probability.p99_us.toFixed(1)} µs`);
      const helixImprovement = ((naive.p99_us - helix.p99_us) / naive.p99_us * 100).toFixed(1);
      const probabilityImprovement = ((naive.p99_us - probability.p99_us) / naive.p99_us * 100).toFixed(1);
      console.log(`  HELIX improvement:       ${helixImprovement}%`);
      console.log(`  Probability improvement: ${probabilityImprovement}%\n`);
    });

    process.exit(0);
  } catch (error) {
    console.error('Error:', error.message);
    process.exit(1);
  }
}

main();
